package main
import (
	"encoding/base64"
	"fmt"
	"os"
	"path/filepath"
)
func main() {
	if len(os.Args) < 2 {
		fmt.Fprintf(os.Stderr, "Usage: sky-extract-stdlib <outdir>\n")
		os.Exit(1)
	}
	outDir := os.Args[1]
	for relPath, content := range embeddedFiles {
		dst := filepath.Join(outDir, relPath)
		os.MkdirAll(filepath.Dir(dst), 0755)
		if err := os.WriteFile(dst, []byte(content), 0644); err != nil {
			fmt.Fprintf(os.Stderr, "Error writing %s: %v\n", dst, err)
			os.Exit(1)
		}
	}
	fmt.Printf("Extracted %d stdlib files to %s\n", len(embeddedFiles), outDir)
}

func extractEmbeddedStdlib(outDir string) bool {
	if len(embeddedFiles) == 0 {
		return false
	}
	for relPath, content := range embeddedFiles {
		dst := filepath.Join(outDir, relPath)
		os.MkdirAll(filepath.Dir(dst), 0755)
		os.WriteFile(dst, []byte(content), 0644)
	}
	return true
}

